parameters.jsCode:
const input = $input.all();

const result = input.map(item => {
  const body = item.json.body;

  const isEmpty = (value) => {
    if (typeof value !== 'string') return value === undefined || value === null;
    return (
      value.trim() === '' ||
      value.trim().toLowerCase() === 'qualquer'
    );
  };

  const isComplete =
    !isEmpty(body.marca_veiculo) &&
    !isEmpty(body.modelo_veiculo) &&
    !isEmpty(body.ano_veiculo) &&
    !isEmpty(body.cor_veiculo) &&
    !isEmpty(body.preco_veiculo);

  return {
    json: {
      resultado: isComplete ? 1 : 0
    }
  };
});

return result;

return $input.all().map(item => {
  const valorStr = item.json.output.preço || '';

  const numero = parseFloat(
    valorStr
      .replace('R$', '')
      .replace(/\./g, '')
      .replace(',', '.')
      .trim()
  );

  return {
    json: {
      ...item.json,
      precoFIPE: numero,
    }
  };
});

// Pega todos os itens do input
const items = $input.all();

return items.map(item => {
  const precoStr = item.json.preco || "";

  // Remove "R$", pontos e espaços, e troca vírgula por ponto para converter em número
  const precoNumerico = Number(
    precoStr.replace("R$", "").replace(/\./g, "").replace(",", ".").trim()
  );

  return {
    json: {
      ...item.json,
      precoLOJA: precoNumerico
    }
  };
});

