// Pega todos os itens de entrada
const items = $input.all();

// Mapeia e retorna apenas os veículos
return items.flatMap(item => {
  const veiculos = item.json.output?.veiculos || [];
  return veiculos.map(veiculo => ({ json: veiculo }));
});

const items = $input.all();
const rawVeiculos = items[0].json.data;

if (!Array.isArray(rawVeiculos) || rawVeiculos.length === 0) {
  return [{ json: { mensagem: "No vehicle found." } }];
}

let mensagem = `*Vehicles Found:*\n\n`;

rawVeiculos.forEach((v) => {
  mensagem += `*${v.marca} ${v.modelo}*\n`;
  mensagem += `  - Year: ${v.ano}\n`;
  mensagem += `  - Color: ${v.cor}\n`;
  mensagem += `  - Price: ${v.preco}\n\n`;
});

mensagem += `Which of these options interested you most?`;

return [{ json: { mensagem } }];

// Read the input JSON
const input = $input.item.json;

// Access the vehicle array
const veiculos = input.data;

// Shuffle helper
function embaralhar(array) {
  return array.sort(() => Math.random() - 0.5);
}

// Pick 3 random vehicles
const selecionados = embaralhar(veiculos).slice(0, 3);

// Build the message with the vehicles
let mensagem = `Unfortunately we do not have the vehicle you requested, but here are some of our options:\n\n`;

selecionados.forEach((v, i) => {
  mensagem += `*${v.marca} ${v.modelo}*\n`;
  mensagem += `   - Year: ${v.ano}\n`;
  mensagem += `   - Color: ${v.cor}\n`;
  mensagem += `   - Price: ${v.preco}\n\n`;
});

mensagem += `How about one of these?`;

// Return a single item
return [{ json: { mensagem } }];

